INSERT INTO biomarker_results (
  report_id, biomarker_key, display_name, display_order, category, value_text, numeric_value, unit,
  reference_text, reference_low, reference_high, status, status_label, quick_takeaway,
  simple_translation, calm_explanation, confidence_label, confidence_score, clinician_questions,
  trend_note
) VALUES
(1, 'ldl', 'LDL Cholesterol', 1, 'Heart health', '142', 142, 'mg/dL', '0–99 mg/dL', 0, 99, 'high', 'Above range', 'Your LDL is above the usual target range and may be worth reviewing soon.', 'LDL is often called the less helpful cholesterol because higher levels can raise heart risk over time.', 'Mild LDL elevations are common and can shift with diet, exercise, weight changes, genetics, and medicines. It is usually something to review thoughtfully, not panic about.', 'Moderate', 0.74, '["Should I repeat my cholesterol panel fasting?","What LDL goal makes sense for my overall risk?"]'::json, 'This result becomes more useful when compared against your later reports.'),
(1, 'hdl', 'HDL Cholesterol', 2, 'Heart health', '43', 43, 'mg/dL', '40–90 mg/dL', 40, 90, 'normal', 'In range', 'Your HDL is in a reassuring range.', 'HDL is often called the helpful cholesterol because higher levels can support heart health.', 'HDL may be influenced by exercise, weight, genetics, smoking, and triglyceride levels. A lower number is worth improving over time, not fearing in the moment.', 'Higher', 0.86, '["What habits would help improve my HDL?","How should I look at HDL together with LDL and triglycerides?"]'::json, 'HDL has been stable across your older reports.'),
(1, 'triglycerides', 'Triglycerides', 3, 'Heart health', '168', 168, 'mg/dL', '0–149 mg/dL', 0, 149, 'high', 'Above range', 'Your triglycerides are above range and could improve with follow-up.', 'Triglycerides are a kind of blood fat that can rise with sugar intake, alcohol, weight changes, or not fasting.', 'A mild rise can happen for simple reasons like a recent meal, alcohol, or insulin resistance. Trends over time matter more than a single number.', 'Moderate', 0.74, '["Do I need to repeat this test fasting?","Could food, alcohol, or medication explain this result?"]'::json, 'Your triglycerides have improved since 2022.'),
(1, 'a1c', 'Hemoglobin A1C', 4, 'Blood sugar', '5.9', 5.9, '%', '4.0–5.6 %', 4.0, 5.6, 'high', 'Above range', 'Your A1C is above the usual range and deserves follow-up.', 'A1C estimates your average blood sugar over about 3 months.', 'A borderline or mildly elevated A1C can happen before diabetes and may improve with habits or treatment. It is important, but usually not a same-day emergency by itself.', 'Moderate', 0.74, '["Should I repeat my A1C or check fasting glucose too?","What changes would make the biggest difference before my next test?"]'::json, 'This is the first point in your A1C timeline.'),
(1, 'glucose', 'Glucose', 5, 'Blood sugar', '104', 104, 'mg/dL', '70–99 mg/dL', 70, 99, 'high', 'Above range', 'Your glucose is a bit higher than expected and should be reviewed in context.', 'Glucose is the amount of sugar in your blood right now.', 'Food, stress, illness, sleep, and fasting status can all affect glucose. One mildly high value is usually not enough to diagnose anything by itself.', 'Moderate', 0.74, '["Was this test fasting, and does that change how we interpret it?","Do I need repeat testing or more blood sugar screening?"]'::json, 'Compare this with later fasting results before drawing conclusions.'),
(1, 'creatinine', 'Creatinine', 6, 'Kidney function', '1.02', 1.02, 'mg/dL', '0.6–1.3 mg/dL', 0.6, 1.3, 'normal', 'In range', 'Your creatinine is in a reassuring range.', 'Creatinine helps estimate how well your kidneys are filtering.', 'Creatinine can shift with hydration, muscle mass, exercise, medicines, and kidney function. Mild changes are not always dangerous, but they do deserve context.', 'Higher', 0.86, '["Could hydration or medication affect this creatinine result?","Do I need kidney follow-up or repeat labs soon?"]'::json, 'Kidney markers remain steady across your saved reports.'),
