INSERT INTO report_questions (report_id, question_text, answer_text, access_tier)
VALUES
(1, 'Should I be worried about my A1C?', 'Your A1C is slightly above the usual range, which is worth following up but usually not a same-day emergency by itself. A good next step is to ask whether repeat testing or fasting glucose would help clarify the picture.', 'free-preview');